// // This module selects between two 32-bit inputs, In1 and In2, based on the value of the Sel input. When Sel is 0, the output Out will reflect the value of In2; when Sel is 1, the output will be driven by In1.
module top_module(Sel,In1,In2,Out);input Sel;
	input[31:0] In1, In2;

	output[31:0] Out;
	wire[31:0] Out;

	assign Out = (Sel)?In2:In1;

endmodule
